// ── 1. Claude 응답 파싱 ──────────────────────────────
const claudeResponse = $input.first().json;
let content = '';

if (claudeResponse.content && claudeResponse.content[0]) {
  content = claudeResponse.content[0].text;
} else {
  throw new Error('Claude 응답 없음: ' + JSON.stringify(claudeResponse));
}

// 마크다운 코드블록 제거 후 JSON 파싱
content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  throw new Error('JSON 파싱 실패. Claude 응답: ' + content.substring(0, 300));
}

// ── 2. 오늘 날짜 보정 (KST) ──────────────────────────
const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
parsed.date = kst.toISOString().split('T')[0];
parsed.updatedAt = kst.toISOString().replace('T', ' ').substring(0, 16) + ' KST';

// ── 3. 기존 history 가져오기 (GitHub GET 노드에서) ────
let existingHistory = [];
try {
  const getResult = $('📥 GitHub SHA 조회').first().json;
  if (getResult.content) {
    const decoded = Buffer.from(getResult.content, 'base64').toString('utf8');
    const existingData = JSON.parse(decoded);
    existingHistory = existingData.history || [];
  }
} catch(e) {
  // 첫 실행이거나 파싱 실패 시 빈 배열로 시작
  existingHistory = [];
}

// ── 4. 오늘 추천을 history에 추가 ────────────────────
if (parsed.recommendation) {
  const todayEntry = {
    date: parsed.date,
    name: parsed.recommendation.nameKr,
    ticker: parsed.recommendation.ticker,
    entryPrice: parsed.recommendation.entryPrice,
    targetPrice: parsed.recommendation.targetPrice,
    currentPrice: null,
    returnPct: null,
    status: 'active'
  };

  // 같은 날짜가 이미 있으면 교체 (재실행 대비)
  existingHistory = existingHistory.filter(h => h.date !== parsed.date);
  existingHistory.unshift(todayEntry);
  existingHistory = existingHistory.slice(0, 10); // 최근 10개 유지
}

parsed.history = existingHistory;

return [{ json: parsed }];
